function solve(nums) {
    const sortedAbs = nums.map(x => Math.abs(x)).sort((a, b) => a - b);
    let count = 0;
    for (let i = 0; i < sortedAbs.length - 1; i++) {
        const target = 2 * sortedAbs[i];
        let low = i + 1;
        let high = sortedAbs.length - 1;
        let res = i;
        while (low <= high) {
            const mid = Math.floor((low + high) / 2);
            if (sortedAbs[mid] <= target) {
                res = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        count += res - i;
    }
    return count;
}
